from string_utils.generation import roman_range

def test_roman_range_zero_step():
    # Test when step is zero, which should raise an error
    try:
        output = list(roman_range(stop=5, start=1, step=0))
    except ValueError as e:
        print(f"Error: {e}")
    except OverflowError as e:
        print(f"Error: {e}")
    else:
        print("No error raised, which is unexpected.")
        output = list(roman_range(stop=5, start=1, step=0))
        assert False, f"Expected an error, but got output: {output}"

